(()=>{document.addEventListener("DOMContentLoaded",()=>{document.querySelectorAll("[data-checkbox-group]").forEach(c=>{let t=c.querySelector("[data-select-all]");if(!t)return;let l=()=>[...c.querySelectorAll('input[type="checkbox"]')].filter(e=>e!==t);function d(){let e=l(),n=e.filter(a=>a.checked).length;t.checked=n===e.length,t.indeterminate=n>0&&n<e.length}d(),t.addEventListener("change",()=>{l().forEach(e=>{e.checked=t.checked})}),c.addEventListener("change",e=>{e.target!==t&&d()})})});})();
